package main

import "fmt"

func solve(prices []int64, strategy []int64, k int64) int64 {
    n := len(prices)
    maxProfit := int64(0)

    // Calculate the original profit
    originalProfit := int64(0)
    for i := 0; i < n; i++ {
        originalProfit += strategy[i] * prices[i]
    }

    // Try all possible k-length consecutive subarrays to modify
    for i := 0; i <= n-k; i++ {
        // Calculate the profit if we modify the subarray from i to i+k-1
        modifiedProfit := originalProfit

        // For the first k/2 elements in the subarray, set strategy to 0 (hold)
        // For the last k/2 elements in the subarray, set strategy to 1 (sell)
        // Adjust the profit accordingly
        for j := 0; j < k; j++ {
            // Original strategy value
            originalVal := strategy[i+j]

            // If the original value was -1 (buy), we need to subtract it from the profit
            if originalVal == -1 {
                modifiedProfit -= prices[i+j]
            }
            // If the original value was 1 (sell), we need to add it to the profit
            if originalVal == 1 {
                modifiedProfit += prices[i+j]
            }

            // If we are in the first half of the subarray, set to 0 (hold)
            if j < k/2 {
                strategy[i+j] = 0
            }
            // If we are in the second half of the subarray, set to 1 (sell)
            if j >= k/2 {
                strategy[i+j] = 1
            }
        }

        // Calculate the profit with the modified subarray
        modifiedProfit = int64(0)
        for j := 0; j < n; j++ {
            modifiedProfit += strategy[j] * prices[j]
        }

        // Update the maximum profit
        if modifiedProfit > maxProfit {
            maxProfit = modifiedProfit
        }

        // Reset the strategy array to its original values
        for j := 0; j < k; j++ {
            strategy[i+j] = originalVal
        }
    }

    return maxProfit
}
